package org.university.api;

import io.swagger.v3.oas.annotations.Operation;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;
import org.university.model.Course;
import org.university.repo.CourseRepository;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/courses")
public class CourseApiController {

    private final CourseRepository courseRepository;

    public CourseApiController(CourseRepository courseRepository) {
        this.courseRepository = courseRepository;
    }

    @Operation(summary = "Get all courses", description = "Returns all courses for any authenticated user")
    @GetMapping
    public ResponseEntity<List<CourseResponse>> getAllCourses() {
        List<CourseResponse> response = courseRepository.findAll()
                .stream()
                .map(CourseResponse::fromEntity)
                .toList();

        return ResponseEntity.ok(response);
    }

    @Operation(summary = "Get course by id", description = "Returns a single course for any authenticated user")
    @GetMapping("/{id}")
    public ResponseEntity<?> getCourseById(@PathVariable Long id) {
        return courseRepository.findById(id)
                .<ResponseEntity<?>>map(course -> ResponseEntity.ok(CourseResponse.fromEntity(course)))
                .orElseGet(() -> ResponseEntity.status(HttpStatus.NOT_FOUND)
                        .body(Map.of("message", "Course not found with id: " + id)));
    }

    @Operation(summary = "Create course", description = "Creates a new course (ADMIN only)")
    @PostMapping
    public ResponseEntity<?> createCourse(@Valid @RequestBody CourseApiRequest request,
                                          Authentication authentication) {
        if (!isAdmin(authentication)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("message", "Only ADMIN users can create courses"));
        }

        Course saved = courseRepository.save(
                new Course(request.getCode(), request.getName(), request.getProfessor())
        );

        return ResponseEntity.status(HttpStatus.CREATED).body(CourseResponse.fromEntity(saved));
    }

    @Operation(summary = "Delete course", description = "Deletes a course by id (ADMIN only)")
    @DeleteMapping("/{id}")
    public ResponseEntity<?> deleteCourse(@PathVariable Long id, Authentication authentication) {
        if (!isAdmin(authentication)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body(Map.of("message", "Only ADMIN users can delete courses"));
        }

        if (!courseRepository.existsById(id)) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(Map.of("message", "Course not found with id: " + id));
        }

        courseRepository.deleteById(id);
        return ResponseEntity.noContent().build();
    }

    private boolean isAdmin(Authentication authentication) {
        return authentication != null
                && authentication.getAuthorities().stream()
                .anyMatch(a -> "ROLE_ADMIN".equals(a.getAuthority()));
    }
}

package org.university.api;

import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.NotBlank;

@Schema(description = "Request payload for creating a course")
public class CourseApiRequest {

    @NotBlank(message = "Course code is required")
    @Schema(example = "CS612")
    private String code;

    @NotBlank(message = "Course name is required")
    @Schema(example = "Web Services")
    private String name;

    @NotBlank(message = "Professor name is required")
    @Schema(example = "Prof. X")
    private String professor;

    public String getCode() {
        return code;
    }

    public void setCode(String code) {
        this.code = code;
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public String getProfessor() {
        return professor;
    }

    public void setProfessor(String professor) {
        this.professor = professor;
    }
}

package org.university.api;

import io.swagger.v3.oas.annotations.media.Schema;
import org.university.model.Course;

@Schema(description = "Course response payload")
public class CourseResponse {

    private Long id;
    private String code;
    private String name;
    private String professor;

    public CourseResponse() {
    }

    public CourseResponse(Long id, String code, String name, String professor) {
        this.id = id;
        this.code = code;
        this.name = name;
        this.professor = professor;
    }

    public static CourseResponse fromEntity(Course course) {
        return new CourseResponse(
                course.getId(),
                course.getCode(),
                course.getName(),
                course.getProfessor()
        );
    }

    public Long getId() {
        return id;
    }

    public String getCode() {
        return code;
    }

    public String getName() {
        return name;
    }

    public String getProfessor() {
        return professor;
    }
}

package org.university.api;

import io.swagger.v3.oas.annotations.Operation;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;
import org.university.model.Enrollment;
import org.university.service.EnrollmentService;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/enrollments")
public class EnrollmentApiController {

    private final EnrollmentService enrollmentService;

    public EnrollmentApiController(EnrollmentService enrollmentService) {
        this.enrollmentService = enrollmentService;
    }

    @Operation(summary = "Enroll in a course", description = "Enrolls the current authenticated user in the given course")
    @PostMapping("/enroll")
    public ResponseEntity<?> enroll(@RequestParam Long courseId, Authentication authentication) {
        String username = authentication.getName();

        try {
            enrollmentService.enroll(username, courseId);

            Enrollment created = enrollmentService.myEnrollments(username).stream()
                    .filter(e -> e.getCourse().getId().equals(courseId))
                    .findFirst()
                    .orElse(null);

            if (created == null) {
                return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body(Map.of("message", "Enrollment was created but could not be retrieved"));
            }

            return ResponseEntity.status(HttpStatus.CREATED).body(EnrollmentResponse.fromEntity(created));
        } catch (IllegalArgumentException ex) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).body(Map.of("message", ex.getMessage()));
        } catch (IllegalStateException ex) {
            return ResponseEntity.status(HttpStatus.CONFLICT).body(Map.of("message", ex.getMessage()));
        }
    }

    @Operation(summary = "Drop a course", description = "Drops enrollment for the current authenticated user by course id")
    @DeleteMapping("/drop/{courseId}")
    public ResponseEntity<?> drop(@PathVariable Long courseId, Authentication authentication) {
        String username = authentication.getName();

        Enrollment existing = enrollmentService.myEnrollments(username).stream()
                .filter(e -> e.getCourse().getId().equals(courseId))
                .findFirst()
                .orElse(null);

        if (existing == null) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(Map.of("message", "Enrollment not found for course id: " + courseId));
        }

        try {
            enrollmentService.drop(username, courseId);
            return ResponseEntity.ok(EnrollmentResponse.fromEntity(existing));
        } catch (IllegalStateException ex) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).body(Map.of("message", ex.getMessage()));
        } catch (IllegalArgumentException ex) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).body(Map.of("message", ex.getMessage()));
        }
    }

    @Operation(summary = "Get my enrollments", description = "Returns all enrollments for the current authenticated user")
    @GetMapping("/my-courses")
    public ResponseEntity<List<EnrollmentResponse>> myCourses(Authentication authentication) {
        String username = authentication.getName();

        List<EnrollmentResponse> response = enrollmentService.myEnrollments(username).stream()
                .map(EnrollmentResponse::fromEntity)
                .toList();

        return ResponseEntity.ok(response);
    }
}

package org.university.api;

import io.swagger.v3.oas.annotations.media.Schema;
import org.university.model.Enrollment;

import java.time.LocalDateTime;

@Schema(description = "Enrollment response payload")
public class EnrollmentResponse {

    private Long id;
    private String courseCode;
    private String courseName;
    private LocalDateTime enrolledAt;

    public EnrollmentResponse() {
    }

    public EnrollmentResponse(Long id, String courseCode, String courseName, LocalDateTime enrolledAt) {
        this.id = id;
        this.courseCode = courseCode;
        this.courseName = courseName;
        this.enrolledAt = enrolledAt;
    }

    public static EnrollmentResponse fromEntity(Enrollment enrollment) {
        return new EnrollmentResponse(
                enrollment.getId(),
                enrollment.getCourse().getCode(),
                enrollment.getCourse().getName(),
                enrollment.getEnrolledAt()
        );
    }

    public Long getId() {
        return id;
    }

    public String getCourseCode() {
        return courseCode;
    }

    public String getCourseName() {
        return courseName;
    }

    public LocalDateTime getEnrolledAt() {
        return enrolledAt;
    }
}

package org.university.api;

import io.swagger.v3.oas.annotations.Operation;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.university.repo.AppUserRepository;

import java.security.Principal;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/users")
public class UserApiController {

    private final AppUserRepository appUserRepository;

    public UserApiController(AppUserRepository appUserRepository) {
        this.appUserRepository = appUserRepository;
    }

    @Operation(summary = "Get current user", description = "Returns the currently authenticated user info without password hash")
    @GetMapping("/me")
    public ResponseEntity<?> me(Principal principal) {
        return appUserRepository.findByUsername(principal.getName())
                .<ResponseEntity<?>>map(user -> ResponseEntity.ok(UserResponse.fromEntity(user)))
                .orElseGet(() -> ResponseEntity.status(HttpStatus.NOT_FOUND)
                        .body(Map.of("message", "User not found for username: " + principal.getName())));
    }
}

package org.university.api;

import io.swagger.v3.oas.annotations.media.Schema;
import org.university.model.AppUser;

@Schema(description = "Current user response payload")
public class UserResponse {

    private Long id;
    private String username;
    private String role;

    public UserResponse() {
    }

    public UserResponse(Long id, String username, String role) {
        this.id = id;
        this.username = username;
        this.role = role;
    }

    public static UserResponse fromEntity(AppUser user) {
        return new UserResponse(user.getId(), user.getUsername(), user.getRole());
    }

    public Long getId() {
        return id;
    }

    public String getUsername() {
        return username;
    }

    public String getRole() {
        return role;
    }
}

package org.university.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {

        http
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/", "/login", "/register", "/h2-console/**").permitAll()
                        .requestMatchers("/dashboard").authenticated()
                        .requestMatchers("/courses/new", "/courses/delete/**").hasRole("ADMIN")
                        .requestMatchers("/courses").hasAnyRole("ADMIN", "STUDENT")
                        .anyRequest().authenticated()
                )
                .formLogin(login -> login
                        .loginPage("/login")
                        .defaultSuccessUrl("/dashboard", true)
                        .permitAll()
                )
                .logout(logout -> logout
                        .logoutSuccessUrl("/")
                        .permitAll()
                )
                .csrf(csrf -> csrf.ignoringRequestMatchers("/h2-console/**"))
                .headers(headers -> headers.frameOptions(frame -> frame.sameOrigin()));

        return http.build();
    }


}

package org.university.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {

        http
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers(
                                "/",
                                "/login",
                                "/register",
                                "/h2-console/**",
                                "/swagger-ui/**",
                                "/swagger-ui.html",
                                "/v3/api-docs/**"
                        ).permitAll()
                        .requestMatchers("/dashboard", "/api/v1/**").authenticated()
                        .requestMatchers("/courses/new", "/courses/delete/**").hasRole("ADMIN")
                        .requestMatchers("/courses").hasAnyRole("ADMIN", "STUDENT")
                        .anyRequest().authenticated()
                )
                .formLogin(login -> login
                        .loginPage("/login")
                        .defaultSuccessUrl("/dashboard", true)
                        .permitAll()
                )
                .logout(logout -> logout
                        .logoutSuccessUrl("/")
                        .permitAll()
                )
                .csrf(csrf -> csrf.ignoringRequestMatchers("/h2-console/**", "/api/v1/**"))
                .headers(headers -> headers.frameOptions(frame -> frame.sameOrigin()));

        return http.build();
    }


}
